class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def linkedListCycle(data):
    values, pos = data.splitlines()
    values = list(map(int, values.split()))
    pos = int(pos)

    if not values:
        return False

    head = ListNode(values[0])
    current = head
    cycle_node = None

    for i in range(1, len(values)):
        current.next = ListNode(values[i])
        current = current.next
        if i == pos:
            cycle_node = current

    if cycle_node:
        current.next = cycle_node

    slow = head
    fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow == fast:
            return True
    return False

