class ListNode {
    int val;
    ListNode next;
    ListNode(int x) {
        val = x;
    }
}
class Solution {
    public boolean linkedListCycle(ListNode data) {
        if (data == null) return false;
        ListNode current = data;
        while (current != null) {
            ListNode runner = current.next;
            while (runner != null) {
                if (runner == current) {
                    return true;
                }
                runner = runner.next;
            }
            current = current.next;
        }
        return false;
    }
}

